import React, { useState } from "react";
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
  Paper,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [docs, setDocs] = useState({ aadharFront: null, aadharBack: null, licenseImage: null });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setFormData((p) => ({ ...p, [e.target.name]: e.target.value }));
  const handleFileChange = (e) => setDocs((p) => ({ ...p, [e.target.name]: e.target.files[0] }));

  const validateEmail = (email) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const validateForm = () => {
    if (!formData.fullName || formData.fullName.trim().length < 2) {
      setError("Please enter your full name.");
      return false;
    }
    if (!validateEmail(formData.email)) {
      setError("Please enter a valid email address.");
      return false;
    }
    if (!/^[6-9]\d{9}$/.test(formData.mobile)) {
      setError("Mobile number must start with 6/7/8/9 and be exactly 10 digits.");
      return false;
    }
    setError("");
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setLoading(true);
    try {
      const res = await signupRider({ ...formData, role: "rider" });
      if (res.data?.success) {
        const token = res.data.token;
        // Upload docs
        const fd = new FormData();
        Object.entries(docs).forEach(([key, file]) => file && fd.append(key, file));
        await uploadRiderDocs(token, fd);

        setSuccess("Rider signup submitted. Pending approval by admin.");
        setTimeout(() => navigate("/rider-login"), 1200);
      } else {
        setError(res.data?.message || "Signup failed. Try again.");
      }
    } catch {
      setError("Server error. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper
        elevation={3}
        sx={{
          mt: 6,
          p: 4,
          borderRadius: 3,
          textAlign: "center",
          fontFamily: "Uber Move, Helvetica Neue, sans-serif",
        }}
      >
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
          Rider Signup
        </Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "gray" }}>
          Join as a rider — upload your documents to get started
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Full Name"
            name="fullName"
            value={formData.fullName}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="email"
            label="Email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />
          <TextField
            fullWidth
            type="tel"
            label="Mobile Number"
            name="mobile"
            value={formData.mobile}
            onChange={handleChange}
            margin="normal"
            inputProps={{
              maxLength: 10,
              pattern: "^[6-9][0-9]{9}$", // ✅ must start with 6-9, exactly 10 digits
            }}
            required
          />

          <Typography sx={{ mt: 2, fontWeight: "bold" }}>Upload Documents</Typography>
          <Box sx={{ mt: 1, textAlign: "left" }}>
            <Typography variant="body2" sx={{ mt: 1 }}>Aadhar Front</Typography>
            <input type="file" name="aadharFront" onChange={handleFileChange} />
            <Typography variant="body2" sx={{ mt: 1 }}>Aadhar Back</Typography>
            <input type="file" name="aadharBack" onChange={handleFileChange} />
            <Typography variant="body2" sx={{ mt: 1 }}>License</Typography>
            <input type="file" name="licenseImage" onChange={handleFileChange} />
          </Box>

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{
              mt: 3,
              bgcolor: "black",
              color: "white",
              fontWeight: "bold",
              "&:hover": { bgcolor: "#333" },
            }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Sign Up"}
          </Button>
        </Box>

        <Typography sx={{ mt: 3 }}>
          Already have a rider account?{" "}
          <Button onClick={() => navigate("/rider-login")} sx={{ color: "black", fontWeight: "bold" }}>
            LOGIN
          </Button>
        </Typography>
        <Typography sx={{ mt: 1 }}>
          Are you a User?{" "}
          <Button onClick={() => navigate("/register")} sx={{ color: "black", fontWeight: "bold" }}>
            USER SIGNUP
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
